useQueryState: Single Parameter

'use client'
import { useQueryState } from 'nuqs'
export function SearchInput() {
const [query, setQuery] = useQueryState('q')
return (
<input
value={query ?? ''}
onChange={(e) => setQuery(e.target.value || null)}
placeholder="Search..."
/>
)
}

Enter fullscreen mode

Exit fullscreen mode

Setting the value to null removes the parameter from the URL entirely — the equivalent of "clear this filter."

Parsers: Type Safety Beyond Strings

import {
parseAsInteger, parseAsFloat, parseAsBoolean,
parseAsArrayOf, parseAsString, parseAsStringEnum, parseAsIsoDate,
} from 'nuqs'
// Page number — URL: ?page=3
const [page, setPage] = useQueryState('page', parseAsInteger.withDefault(1))
// Multi-select — URL: ?tags=react,typescript
const [tags, setTags] = useQueryState('tags', parseAsArrayOf(parseAsString).withDefault([]))
// Enum — URL: ?sort=price_asc
const [sort, setSort] = useQueryState(
'sort',
parseAsStringEnum(['name_asc', 'name_desc', 'price_asc', 'price_desc'] as const).withDefault('name_asc')
)
// Date — URL: ?from=2026-01-01
const [from, setFrom] = useQueryState('from', parseAsIsoDate)

Enter fullscreen mode

Exit fullscreen mode

.withDefault(value) means the hook returns the default when the parameter is absent, instead of null.

useQueryStates: Multiple Parameters Together

When parameters belong together, update them atomically:

import { useQueryStates, parseAsInteger, parseAsString, parseAsStringEnum } from 'nuqs'
export function useTableState() {
return useQueryStates({
page: parseAsInteger.withDefault(1),
perPage: parseAsInteger.withDefault(20),
q: parseAsString.withDefault(''),
sortBy: parseAsStringEnum(['name', 'email', 'createdAt'] as const).withDefault('createdAt'),
sortDir: parseAsStringEnum(['asc', 'desc'] as const).withDefault('desc'),
})
}
function UsersTable() {
const [{ page, perPage, q, sortBy, sortDir }, setTableState] = useTableState()
function handleSort(field: 'name' | 'email' | 'createdAt') {
setTableState({
sortBy: field,
sortDir: sortBy === field && sortDir === 'asc' ? 'desc' : 'asc',
page: 1, // reset page on sort change
})
}
}

Enter fullscreen mode

Exit fullscreen mode

setTableState accepts a partial object — only specified keys update.

Navigation Options

// Trigger full server re-render (re-fetches Server Components)
setValue(value, { shallow: false })
// Push to history (back button returns to previous filter state)
setValue(value, { history: 'push' })
// Throttle URL writes (useful for live search inputs)
setValue(value, { throttleMs: 200 })

Enter fullscreen mode

Exit fullscreen mode

shallow: false is critical for App Router: it makes the URL update trigger a real navigation so Server Components that read searchParams get the new values.

Server Component Integration

// lib/search-params.ts
import { createSearchParamsCache, parseAsInteger, parseAsString } from 'nuqs/server'
export const searchParamsCache = createSearchParamsCache({
page: parseAsInteger.withDefault(1),
perPage: parseAsInteger.withDefault(20),
q: parseAsString.withDefault(''),
status: parseAsStringEnum(['active', 'inactive', 'all'] as const).withDefault('all'),
})

Enter fullscreen mode

Exit fullscreen mode

// app/users/page.tsx (Server Component)
import { searchParamsCache } from '@/lib/search-params'
export default async function UsersPage({ searchParams }) {
const { page, perPage, q, status } = searchParamsCache.parse(await searchParams)
const users = await db.query.users.findMany({
where: and(
q ? ilike(users.name, `%${q}%`) : undefined,
status !== 'all' ? eq(users.status, status) : undefined,
),
offset: (page - 1) * perPage,
limit: perPage,
})
return <UsersTable initialUsers={users} />
}

Enter fullscreen mode

Exit fullscreen mode

The same parsers serve both server (DB query) and client (filter controls).

Real Pattern: Filters with startTransition

'use client'
export function UserFilters() {
const [isPending, startTransition] = useTransition()
const [filters, setFilters] = useQueryStates({
q: parseAsString.withDefault(''),
status: parseAsStringEnum(['all', 'active', 'inactive'] as const).withDefault('all'),
page: parseAsInteger.withDefault(1),
})
function updateFilter(key: keyof typeof filters, value: any) {
startTransition(() => {
setFilters({ [key]: value, page: 1 }, { shallow: false })
})
}
return (
<div className={cn('flex gap-3', isPending && 'opacity-60 pointer-events-none')}>
<Input
value={filters.q}
onChange={(e) => updateFilter('q', e.target.value || '')}
placeholder="Search..."
/>
<Select value={filters.status} onValueChange={(v) => updateFilter('status', v)}>
<SelectTrigger className="w-36"><SelectValue /></SelectTrigger>
<SelectContent>
<SelectItem value="all">All</SelectItem>
<SelectItem value="active">Active</SelectItem>
<SelectItem value="inactive">Inactive</SelectItem>
</SelectContent>
</Select>
{(filters.q || filters.status !== 'all') && (
<Button variant="ghost" size="sm"
onClick={() => setFilters({ q: '', status: 'all', page: 1 }, { shallow: false })}>
Clear
</Button>
)}
</div>
)
}

