// Setup
<NuqsAdapter>{children}</NuqsAdapter>

// Single param
const [value, setValue] = useQueryState('key', parser.withDefault(default))
// Multiple params (atomic)
const [state, setState] = useQueryStates({ key1: parser1, key2: parser2 })
// Common parsers
parseAsString | parseAsInteger | parseAsFloat | parseAsBoolean
parseAsArrayOf(p) | parseAsStringEnum([]) | parseAsIsoDate | parseAsJson(schema)
// Options
setValue(v, { shallow: false }) // trigger server re-render
setValue(v, { history: 'push' }) // add to history
setValue(v, { throttleMs: 300 }) // debounce
// Server
import { createSearchParamsCache } from 'nuqs/server'
const cache = createSearchParamsCache({ page: parseAsInteger.withDefault(1) })
const { page } = cache.parse(await searchParams)

